import re

def scan_pii_in_output(output: str) -> list:
    patterns = {
        'email': r'\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b',
        'phone': r'\b\d{3}[-.]?\d{3}[-.]?\d{4}\b',
        'ssn': r'\b\d{3}-\d{2}-\d{4}\b'
    }
    findings = []
    for pii_type, pattern in patterns.items():
        matches = re.findall(pattern, output)
        if matches:
            findings.extend([{'type': pii_type, 'match': m} for m in matches])
    return findings

# Usage in CrewAI
def check_agent_output(task_output):
    leaks = scan_pii_in_output(task_output)
    if leaks:
        print(f'PII detected: {leaks}')
    return len(leaks) == 0

from crewai import Crew

def monitor_crew_memory(crew: Crew):
    sensitive_keywords = ['password', 'api_key', 'secret', 'token', 'key=']
    memory_content = crew.memory.get_all()
    leaks = []
    for msg in memory_content:
        content = msg.get('content', '')
        for keyword in sensitive_keywords:
            if keyword.lower() in content.lower():
                leaks.append({'message': msg, 'keyword': keyword})
    return leaks

