import json

def validate_tool_output(tool_name: str, output: any) -> bool:
    output_str = json.dumps(output) if isinstance(output, (dict, list)) else str(output)
    # Check for common sensitive patterns
    if re.search(r'(?i)(password|secret|key|token|auth)[=:][\s\w\.-]+', output_str):
        print(f'Potential leak in tool {tool_name}: {output_str[:100]}')
        return False
    return True

