import re

def redact_pii(text: str) -> str:
    patterns = [
        (r'\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b', '[EMAIL]'),
        (r'\b\d{3}[-.]?\d{3}[-.]?\d{4}\b', '[PHONE]'),
        (r'\b\d{3}-\d{2}-\d{4}\b', '[SSN]'),
        (r'(?i)(password|secret|key|token)[\s=:](\S+)', r'\1=[REDACTED]')
    ]
    for pattern, replacement in patterns:
        text = re.sub(pattern, replacement, text)
    return text

# CrewAI agent callback
class SafeAgent:
    def __init__(self, agent):
        self.agent = agent

    def execute_task(self, task):
        raw_output = self.agent.execute_task(task)
        safe_output = redact_pii(raw_output)
        return safe_output

from crewai import Crew

def safe_memory_store(crew: Crew, content: str):
    # Only store if no sensitive data
    if not contains_sensitive(content):
        crew.memory.add(content)
    else:
        crew.memory.add('[REDACTED CONTENT]')

def contains_sensitive(text: str) -> bool:
    sensitive = ['api_key', 'password', 'secret', 'token', 'private_key']
    return any(word in text.lower() for word in sensitive)

# Override crew memory
class SecureCrew(Crew):
    def delegate_work(self):
        super().delegate_work()
        # Scan and clean memory post-execution
        for msg in self.memory.get_all():
            if contains_sensitive(msg.get('content', '')):
                msg['content'] = '[REDACTED]'

from crewai import Task

def validate_task_input(task: Task, input_data: str) -> bool:
    blocked_patterns = [
        r'api[_\s]?key[\s=:]+\S+',
        r'password[\s=:]\S+',
        r'bearer\s+\S+',
        r'x-api-key[\s=:]\S+'
    ]
    for pattern in blocked_patterns:
        if re.search(pattern, input_data, re.IGNORECASE):
            raise ValueError(f'Blocked sensitive input in task {task.description}')
    return True

# Usage
for task in crew.tasks:
    validate_task_input(task, task.input or '')
